import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.Cr-Z7ngm.js";const T=JSON.parse('{"title":"行情数据字段介绍","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"market-data/data-fields.md","filePath":"zh-CN/market-data/data-fields.md"}'),o={name:"market-data/data-fields.md"};function h(i,t,l,s,n,_){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="行情数据字段介绍" tabindex="-1">行情数据字段介绍 <a class="header-anchor" href="#行情数据字段介绍" aria-label="Permalink to &quot;行情数据字段介绍&quot;">​</a></h1><p>基本指标、财务指标的定义、计算公式及港美股特殊说明。</p><h2 id="基本指标" tabindex="-1">基本指标 <a class="header-anchor" href="#基本指标" aria-label="Permalink to &quot;基本指标&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>定义</th><th>公式</th></tr></thead><tbody><tr><td>总市值</td><td>所有普通股的市场价格总和</td><td>总股本 × 最新价</td></tr><tr><td>流通市值</td><td>可在交易所流通的股票市值</td><td>流通股本 × 最新价</td></tr><tr><td>总股本</td><td>公司发行且未被回购的全部普通股总数</td><td>—</td></tr><tr><td>流通股本</td><td>可在交易所流通、未被锁定或限制交易的股份数量</td><td>—</td></tr><tr><td>换手率</td><td>股票在一定时间内转手买卖的频率</td><td>成交量 ÷ 流通股本 × 100%</td></tr><tr><td>振幅</td><td>当日最高价和最低价的差值与昨收价的百分比</td><td>（当日最高价 - 当日最低价）÷ 昨收价 × 100%</td></tr><tr><td>委比</td><td>衡量买卖盘相对强度的指标，取值 -100% 到 +100%</td><td>（委买手数 - 委卖手数）÷（委买手数 + 委卖手数）× 100%</td></tr><tr><td>量比</td><td>当前平均每分钟成交量与过去 5 日平均每分钟成交量之比</td><td>（现总成交量 ÷ 现累计开市分钟数）÷ 过去 5 日平均每分钟成交量</td></tr><tr><td>均价</td><td>一个交易日内的平均交易价格</td><td>总成交额 ÷ 总成交量</td></tr><tr><td>折/溢价率</td><td>ETF 基金净值和市场价格的偏离比率</td><td>（现价 - 基金净值）÷ 基金净值</td></tr><tr><td>52 周最高</td><td>过去 52 周内达到的最高价格</td><td>—</td></tr><tr><td>52 周最低</td><td>过去 52 周内达到的最低价格</td><td>—</td></tr></tbody></table><p>注：委比按用户行情权限的档位数据计算，无行情档位数据时委比为空。</p><h2 id="财务指标" tabindex="-1">财务指标 <a class="header-anchor" href="#财务指标" aria-label="Permalink to &quot;财务指标&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>定义</th><th>公式</th></tr></thead><tbody><tr><td>每股收益（TTM）</td><td>过去 12 个月每股普通股的收益</td><td>最近 12 个月净利润 ÷ 最新总股本</td></tr><tr><td>市盈率（TTM）</td><td>滚动市盈率，基于最近四个季度净利润</td><td>最新价 ÷ 每股收益（TTM）</td></tr><tr><td>每股收益（动）</td><td>根据最新财报估算的全年每股收益</td><td>截止最新财报净利润 ÷ 财报月份数 × 12 ÷ 最新总股本</td></tr><tr><td>市盈率（动）</td><td>动态市盈率，反映公司成长性</td><td>最新价 ÷ 每股收益（动）</td></tr><tr><td>每股收益（静）</td><td>基于最近一个完整年度的每股收益</td><td>最近年报净利润 ÷ 最新总股本</td></tr><tr><td>市盈率（静）</td><td>静态市盈率，基于上一年实际盈利</td><td>最新价 ÷ 每股收益（静）</td></tr><tr><td>每股净资产</td><td>每股股票的账面价值</td><td>截止最新财报普通股股东权益 ÷ 最新总股本</td></tr><tr><td>市净率</td><td>每股股价与每股净资产的比率</td><td>最新价 ÷ 每股净资产</td></tr><tr><td>股息（TTM）</td><td>过去 12 个月每股派发的股息</td><td>最近 12 个月股息总额 ÷ 最新总股本</td></tr><tr><td>股息率（TTM）</td><td>每股股息与当前股价的比率</td><td>股息（TTM）÷ 最新价 × 100%</td></tr></tbody></table><p>注：港股市场每股收益采用归属母公司所有者的净利润口径。美股总股本不含已回购库存股。</p>',8)])])}const b=d(o,[["render",h]]);export{T as __pageData,b as default};
